  ('disabled-64311456-moex-00334', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '於中度颱風侵臺前夕，甲大學潛水隊不顧交通部中央氣象局已發布颱風警 報及東北角暨宜蘭海岸國家風景區之預先警告，仍堅持原行程潛水，結果 造成隊員乙遇難身亡。下列敘述何者正確？', '["乙從事冒險性活動，因風景區管理機關既已為適當之警告，故不須負國 賠責任", "基於保護規範理論，因風景區管理機關未加以攔阻，仍須負不作為之國 賠責任", "乙從事冒險性活動，風景區管理機關雖未攔阻但已有警告，故可減輕國 賠責任", "基於保護規範理論，風景區管理機關須要求乙簽下切結書，始可免除國 賠責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
